"""Audit — cross-reference manifest against filesystem (read-only).

Public API:
    AuditResult  – dataclass with missing/stale/untracked lists
    run_audit()  – main entry point; returns AuditResult
"""

from __future__ import annotations

from dataclasses import dataclass, field
from pathlib import Path

from model_shelf.manifest import (
    _sha256_dir_for_rebuild,
    build_tracked_path_set,
    load_manifest,
    should_skip_shelf_path,
)
from model_shelf.import_model import _sha256_file
from model_shelf.resolver import (
    SUPPORTED_FORMATS,
    Config,
    check_storage_available,
)


@dataclass
class AuditResult:
    """Result of a shelf audit."""

    missing: list[str] = field(default_factory=list)
    untracked: list[str] = field(default_factory=list)
    stale: list[str] = field(default_factory=list)

    def to_dict(self) -> dict:
        return {
            "missing": list(self.missing),
            "untracked": list(self.untracked),
            "stale": list(self.stale),
        }


def _check_manifest_entries(
    shelf_root: Path, models: dict
) -> tuple[list[str], list[str]]:
    """Check manifest entries against filesystem.

    Returns (missing, stale) lists.
    """
    missing: list[str] = []
    stale: list[str] = []

    for repo_id, entry in models.items():
        fmt = entry.get("format", "")
        if fmt not in SUPPORTED_FORMATS or "/" not in repo_id:
            continue

        publisher, _, repo_name = repo_id.partition("/")
        model_dir = shelf_root / fmt / publisher / repo_name

        # Check every tracked file exists
        for fname in entry.get("files", []):
            if not (model_dir / fname).is_file():
                missing.append(repo_id)
                break
        else:
            # All files exist — verify SHA256
            entry_sha = entry.get("sha256", "")
            if fmt == "gguf":
                gguf_files = entry.get("files", [])
                if gguf_files:
                    try:
                        actual = _sha256_file(model_dir / gguf_files[0])
                    except OSError:
                        missing.append(repo_id)
                        continue
                    if actual != entry_sha:
                        stale.append(repo_id)
            else:
                if model_dir.is_dir():
                    try:
                        actual = _sha256_dir_for_rebuild(model_dir)
                    except OSError:
                        missing.append(repo_id)
                        continue
                    if actual != entry_sha:
                        stale.append(repo_id)
                else:
                    missing.append(repo_id)

    return missing, stale


def _find_untracked_files(
    shelf_root: Path, tracked_paths: set[str]
) -> list[str]:
    """Walk shelf and find files not in *tracked_paths*."""
    untracked: list[str] = []
    for fmt in SUPPORTED_FORMATS:
        fmt_dir = shelf_root / fmt
        if not fmt_dir.is_dir():
            continue
        for f in fmt_dir.rglob("*"):
            if not f.is_file():
                continue
            if should_skip_shelf_path(f):
                continue
            f_str = str(f)
            if f_str not in tracked_paths:
                untracked.append(f_str)
    return untracked


def run_audit(config: Config) -> AuditResult:
    """Cross-reference manifest entries against the filesystem.

    Returns AuditResult with missing, stale, and untracked lists.
    """
    check_storage_available(config)
    shelf_root = config.shelf_root

    manifest = load_manifest(shelf_root)
    models = manifest.get("models", {})

    tracked_paths = build_tracked_path_set(shelf_root, models)

    missing, stale = _check_manifest_entries(shelf_root, models)
    untracked = _find_untracked_files(shelf_root, tracked_paths)

    return AuditResult(
        missing=sorted(missing),
        untracked=sorted(untracked),
        stale=sorted(stale),
    )

"""Remove a model from the shelf by repo_id.

Public API:
    RemoveResult           – dataclass with removed paths and hardlink warnings
    remove_model()         – main entry point; dry-run by default
    cleanup_empty_parents() – remove empty ancestor dirs (shared with cli.py)
"""

from __future__ import annotations

import os

from dataclasses import dataclass, field
from pathlib import Path

from model_shelf.manifest import load_manifest, remove_manifest_entry
from model_shelf.resolver import (
    SUPPORTED_FORMATS,
    Config,
    check_storage_available,
)


@dataclass
class RemoveResult:
    """Result of a remove operation (dry-run or execute)."""

    removed: list[str] = field(default_factory=list)
    hardlinks_warn: list[str] = field(default_factory=list)

    def to_dict(self) -> dict:
        return {
            "removed": list(self.removed),
            "hardlinks_warn": list(self.hardlinks_warn),
        }


def cleanup_empty_parents(shelf_root: Path, model_dir: Path) -> None:
    """Remove empty ancestor directories up to (but not including) shelf_root.

    Canonical implementation shared by remove.py and cli.py (gc cleanup).
    """
    parent = model_dir
    while parent != shelf_root:
        try:
            if parent.is_dir() and not any(parent.iterdir()):
                parent.rmdir()
            else:
                break
        except OSError:
            break
        parent = parent.parent


def _collect_model_files(
    shelf_root: Path, fmt: str, repo_id: str, entry: dict
) -> list[Path]:
    """Collect existing file paths for a model entry."""
    publisher, _, repo_name = repo_id.partition("/")
    model_dir = shelf_root / fmt / publisher / repo_name
    paths: list[Path] = []
    for fname in entry.get("files", []):
        fp = model_dir / fname
        if fp.is_file():
            paths.append(fp)
    return paths


def _delete_files_and_warn(paths: list[Path]) -> RemoveResult:
    """Delete files, warn on hardlinks. Returns RemoveResult for execute path."""
    hardlinks_warn: list[str] = []
    removed_paths: list[str] = []
    for fp in paths:
        try:
            st = fp.stat()
        except OSError:
            continue
        if st.st_nlink > 1:
            hardlinks_warn.append(f"{fp} (st_nlink={st.st_nlink})")
        removed_paths.append(str(fp))
        try:
            os.unlink(fp)
        except OSError:
            pass
    return RemoveResult(removed=removed_paths, hardlinks_warn=hardlinks_warn)


def remove_model(
    config: Config, repo_id: str, *, dry_run: bool = True
) -> RemoveResult:
    """Remove the model identified by *repo_id* from the shelf.

    Raises ValueError if *repo_id* is not found in the manifest.
    """
    check_storage_available(config)
    shelf_root = config.shelf_root

    manifest = load_manifest(shelf_root)
    models = manifest.get("models", {})

    entry = models.get(repo_id)
    if entry is None:
        raise ValueError(f"model '{repo_id}' not found in manifest")

    fmt = entry.get("format", "")
    if fmt not in SUPPORTED_FORMATS:
        raise ValueError(
            f"unsupported format {fmt!r} in manifest entry for '{repo_id}'"
        )

    publisher, _, repo_name = repo_id.partition("/")
    model_dir = shelf_root / fmt / publisher / repo_name
    all_paths = _collect_model_files(shelf_root, fmt, repo_id, entry)

    if dry_run:
        hardlinks_warn: list[str] = []
        for fp in all_paths:
            try:
                st = fp.stat()
            except OSError:
                continue
            if st.st_nlink > 1:
                hardlinks_warn.append(f"{fp} (st_nlink={st.st_nlink})")
        return RemoveResult(
            removed=[str(p) for p in all_paths],
            hardlinks_warn=hardlinks_warn,
        )

    # Execute
    result = _delete_files_and_warn(all_paths)
    remove_manifest_entry(shelf_root, repo_id)
    cleanup_empty_parents(shelf_root, model_dir)
    return result

"""Garbage collection — find and clean up incomplete downloads, orphaned
files, and empty directories on the curated shelf.

Dry-run by default.  Never touches .cache/ or dot-prefixed paths.

Public API:
    GCResult  – dataclass with lists and reclaimable byte count
    run_gc()  – main entry point (scan-only; execution happens in CLI)
"""

from __future__ import annotations

import os
import shutil

from dataclasses import dataclass, field
from pathlib import Path

from model_shelf.manifest import (
    build_tracked_path_set,
    load_manifest,
    should_skip_shelf_path,
)
from model_shelf.resolver import (
    SUPPORTED_FORMATS,
    Config,
    check_storage_available,
)


@dataclass
class GCResult:
    """Result of a garbage-collection scan."""

    incomplete_downloads: list[str] = field(default_factory=list)
    orphaned_files: list[str] = field(default_factory=list)
    empty_dirs: list[str] = field(default_factory=list)
    total_reclaimable_bytes: int = 0

    def to_dict(self) -> dict:
        return {
            "incomplete_downloads": list(self.incomplete_downloads),
            "orphaned_files": list(self.orphaned_files),
            "empty_dirs": list(self.empty_dirs),
            "total_reclaimable_bytes": self.total_reclaimable_bytes,
        }


def _find_incomplete_downloads(shelf_root: Path) -> list[str]:
    """Find model dirs that appear to be incomplete downloads."""
    incomplete: list[str] = []
    for fmt in SUPPORTED_FORMATS:
        fmt_dir = shelf_root / fmt
        if not fmt_dir.is_dir():
            continue
        for publisher in sorted(fmt_dir.iterdir()):
            if not publisher.is_dir() or should_skip_shelf_path(publisher):
                continue
            for repo in sorted(publisher.iterdir()):
                if not repo.is_dir() or should_skip_shelf_path(repo):
                    continue
                repo_str = str(repo)
                if fmt == "gguf":
                    gguf_files = [
                        f for f in repo.glob("*.gguf")
                        if not should_skip_shelf_path(f)
                    ]
                    if not gguf_files:
                        incomplete.append(repo_str)
                elif fmt == "mlx":
                    if not (repo / "config.json").is_file():
                        incomplete.append(repo_str)
                else:  # safetensors
                    config_json = repo / "config.json"
                    if not config_json.is_file():
                        incomplete.append(repo_str)
                    else:
                        st_files = [
                            f for f in repo.glob("*.safetensors")
                            if not should_skip_shelf_path(f)
                        ]
                        if not st_files:
                            incomplete.append(repo_str)
    return incomplete


def _find_orphaned_files(
    shelf_root: Path, tracked_set: set[str]
) -> tuple[list[str], int]:
    """Find files on shelf not in manifest. Returns (paths, total_bytes)."""
    orphaned: list[str] = []
    reclaimable: int = 0
    scanned_dirs: set[str] = set()

    for fmt in SUPPORTED_FORMATS:
        fmt_dir = shelf_root / fmt
        if not fmt_dir.is_dir():
            continue
        for publisher in sorted(fmt_dir.iterdir()):
            if not publisher.is_dir() or should_skip_shelf_path(publisher):
                continue
            for repo in sorted(publisher.iterdir()):
                if not repo.is_dir() or should_skip_shelf_path(repo):
                    continue
                scanned_dirs.add(str(repo))
                for f in sorted(repo.rglob("*")):
                    if not f.is_file() or should_skip_shelf_path(f):
                        continue
                    f_str = str(f)
                    if f_str not in tracked_set:
                        orphaned.append(f_str)
                        try:
                            reclaimable += f.stat().st_size
                        except OSError:
                            pass

            # Also scan for loose files at publisher level (no repo subdir)
            for f in sorted(publisher.rglob("*")):
                if not f.is_file() or should_skip_shelf_path(f):
                    continue
                parent_str = str(f.parent)
                if parent_str in scanned_dirs:
                    continue
                f_str = str(f)
                if f_str not in tracked_set:
                    orphaned.append(f_str)
                    try:
                        reclaimable += f.stat().st_size
                    except OSError:
                        pass

    return orphaned, reclaimable


def _find_empty_dirs(shelf_root: Path) -> list[str]:
    """Find empty directories on the shelf (deepest first)."""
    empty: list[str] = []
    for fmt in SUPPORTED_FORMATS:
        fmt_dir = shelf_root / fmt
        if not fmt_dir.is_dir():
            continue
        all_dirs = sorted(
            (d for d in fmt_dir.rglob("*") if d.is_dir()),
            key=lambda d: -len(d.parts),
        )
        for d in all_dirs:
            if should_skip_shelf_path(d):
                continue
            try:
                contents = [
                    c for c in d.iterdir()
                    if not should_skip_shelf_path(c)
                ]
            except OSError:
                continue
            if not contents:
                empty.append(str(d))
    return empty


def run_gc(config: Config) -> GCResult:
    """Scan the shelf for reclaimable space.

    Returns GCResult with incomplete downloads, orphaned files, empty
    directories, and total reclaimable bytes. This function is read-only;
    the CLI handler performs actual deletion when --execute is passed.
    """
    check_storage_available(config)
    shelf_root = config.shelf_root

    manifest = load_manifest(shelf_root)
    models = manifest.get("models", {})
    tracked_set = build_tracked_path_set(shelf_root, models)

    incomplete = _find_incomplete_downloads(shelf_root)
    orphaned, reclaimable = _find_orphaned_files(shelf_root, tracked_set)
    empty_dirs = _find_empty_dirs(shelf_root)

    return GCResult(
        incomplete_downloads=sorted(incomplete),
        orphaned_files=sorted(orphaned),
        empty_dirs=sorted(empty_dirs),
        total_reclaimable_bytes=reclaimable,
    )

